import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> (requested, resolved)
def build_index(data):
    idx = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                idx[(name, fw['framework'], pkg['id'])] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return idx

b = build_index(baseline)
a = build_index(after)

changes = []
unchanged = []
all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv and av:
        if bv[1] != av[1]:
            changes.append((proj, fw, pkg, bv[1], av[1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, av[1]))
    elif bv and not av:
        changes.append((proj, fw, pkg, bv[1], '-', 'Removed'))
    elif av and not bv:
        changes.append((proj, fw, pkg, '-', av[1], 'Added'))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<15} {\"Framework\":<10} {\"Package\":<45} {\"Before\":<12} {\"After\":<12} Status')
    for c in changes:
        print(f'{c[0]:<15} {c[1]:<10} {c[2]:<45} {c[3]:<12} {c[4]:<12} {c[5]}')
else:
    print('No changes detected.')

print()
print(f'UNCHANGED: {len(unchanged)} package-project combinations resolve identically.')
"

